+        }
+        if self.flush_docs_threshold == 0 {
+            return Err("search.indexing.flush_docs_threshold must be >= 1".to_string());
+        }
+        if self.max_docs_per_second == 0 {
+            return Err("search.indexing.max_docs_per_second must be >= 1".to_string());
+        }
+        Ok(())
+    }
